"use strict";(self.webpackChunkclassic=self.webpackChunkclassic||[]).push([[8581],{5610:e=>{e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Welcome to ExpressoTS","href":"/docs/hello","docId":"hello"},{"type":"category","label":"Overview","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Introduction","href":"/docs/overview/intro","docId":"overview/intro"},{"type":"link","label":"First steps","href":"/docs/overview/first-steps","docId":"overview/first-steps"},{"type":"link","label":"Application","href":"/docs/overview/application","docId":"overview/application"},{"type":"link","label":"App Container","href":"/docs/overview/app-container","docId":"overview/app-container"},{"type":"link","label":"Modules","href":"/docs/overview/module","docId":"overview/module"},{"type":"link","label":"Middleware","href":"/docs/overview/middleware","docId":"overview/middleware"},{"type":"link","label":"Controllers","href":"/docs/overview/controller","docId":"overview/controller"},{"type":"link","label":"Use Cases","href":"/docs/overview/usecase","docId":"overview/usecase"},{"type":"link","label":"Providers","href":"/docs/overview/providers","docId":"overview/providers"},{"type":"link","label":"Repositories","href":"/docs/overview/repositories","docId":"overview/repositories"},{"type":"link","label":"Entities","href":"/docs/overview/entities","docId":"overview/entities"},{"type":"link","label":"Decorators","href":"/docs/overview/decorators","docId":"overview/decorators"},{"type":"link","label":"Dependency Injection","href":"/docs/overview/di","docId":"overview/di"},{"type":"link","label":"Dependencies","href":"/docs/overview/dependencies","docId":"overview/dependencies"},{"type":"link","label":"Status Code","href":"/docs/overview/status-code","docId":"overview/status-code"},{"type":"link","label":"Error Handling","href":"/docs/overview/error-handling","docId":"overview/error-handling"},{"type":"link","label":"Test","href":"/docs/overview/test","docId":"overview/test"},{"type":"link","label":"Render","href":"/docs/overview/render","docId":"overview/render"}],"href":"/docs/category/overview"},{"type":"category","label":"Code By Example","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Bootstrap Method","href":"/docs/codebyexample/bootstrap","docId":"codebyexample/bootstrap"},{"type":"link","label":"Application Container","href":"/docs/codebyexample/app-container","docId":"codebyexample/app-container"},{"type":"link","label":"Modules","href":"/docs/codebyexample/modules","docId":"codebyexample/modules"},{"type":"link","label":"Controllers","href":"/docs/codebyexample/controller","docId":"codebyexample/controller"},{"type":"link","label":"Use Cases","href":"/docs/codebyexample/usecase","docId":"codebyexample/usecase"},{"type":"link","label":"Entities","href":"/docs/codebyexample/entities","docId":"codebyexample/entities"},{"type":"link","label":"ExpressoTS Utilities","href":"/docs/codebyexample/utils","docId":"codebyexample/utils"}],"href":"/docs/category/code-by-example"},{"type":"category","label":"CLI","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Overview","href":"/docs/cli/overview","docId":"cli/overview"},{"type":"link","label":"Generate","href":"/docs/cli/generate","docId":"cli/generate"}],"href":"/docs/category/cli"},{"type":"category","label":"Providers","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"DTO Validator","href":"/docs/providers/dto-validator","docId":"providers/dto-validator"},{"type":"link","label":"Environment Validator","href":"/docs/providers/envvalidator","docId":"providers/envvalidator"},{"type":"link","label":"In Memory DB","href":"/docs/providers/in-memory-db","docId":"providers/in-memory-db"},{"type":"link","label":"Prisma Provider","href":"/docs/providers/prisma","docId":"providers/prisma"}],"href":"/docs/category/providers"},{"type":"category","label":"Tutorials","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Compression","href":"/docs/tutorials/compression","docId":"tutorials/compression"},{"type":"link","label":"Cookies","href":"/docs/tutorials/cookies","docId":"tutorials/cookies"}],"href":"/docs/category/tutorials"},{"type":"link","label":"Roadmap","href":"/docs/roadmap","docId":"roadmap"},{"type":"link","label":"Governance","href":"/docs/governance","docId":"governance"}]},"docs":{"cli/generate":{"id":"cli/generate","title":"Generate","description":"In order to provide a better developer experience, the ExpressoTS CLI provides a set of commands to help you scaffold the application resources such as use cases, controllers, DTO\'s, providers and services.","sidebar":"tutorialSidebar"},"cli/overview":{"id":"cli/overview","title":"Overview","description":"The ExpressoTS CLI is a command-line interface tool that helps you to create ExpressoTS projects and scaffold the application resources such as use cases, controllers, dto\'s, providers and services.","sidebar":"tutorialSidebar"},"codebyexample/app-container":{"id":"codebyexample/app-container","title":"Application Container","description":"The application container is a dependency injection container. See Application Container for more information.","sidebar":"tutorialSidebar"},"codebyexample/bootstrap":{"id":"codebyexample/bootstrap","title":"Bootstrap Method","description":"The bootstrap method is the entry point of your application. It is responsible for loading the application configuration, registering middlewares, and starting the application.","sidebar":"tutorialSidebar"},"codebyexample/controller":{"id":"codebyexample/controller","title":"Controllers","description":"Controllers are responsible for handling incoming requests and returning responses to the client.","sidebar":"tutorialSidebar"},"codebyexample/entities":{"id":"codebyexample/entities","title":"Entities","description":"Entities are the core of your application. They are the representation of your business objects. For more information about entities, see Entities.","sidebar":"tutorialSidebar"},"codebyexample/modules":{"id":"codebyexample/modules","title":"Modules","description":"Modules are responsible for registering controllers. See Modules for more information.","sidebar":"tutorialSidebar"},"codebyexample/usecase":{"id":"codebyexample/usecase","title":"Use Cases","description":"Uses cases are the implementation of the business logic of your application. For more information about use cases, see Use Cases.","sidebar":"tutorialSidebar"},"codebyexample/utils":{"id":"codebyexample/utils","title":"ExpressoTS Utilities","description":"Status Codes","sidebar":"tutorialSidebar"},"governance":{"id":"governance","title":"Governance","description":"ExpressoTS is built by its community. We welcome and appreciate contributions of all kinds. There are many ways to help, from reporting issues, contributing code, and helping us improve our community.","sidebar":"tutorialSidebar"},"hello":{"id":"hello","title":"Welcome to ExpressoTS","description":"ExpressoTS is designed to simplify the software development process, enabling developers to concentrate on the core business logic by abstracting technical complexities. Our goal is to enhance your productivity through a framework that not only accelerates development but also offers comprehensive documentation and a superior developer experience, minimizing the necessity for boilerplate code.","sidebar":"tutorialSidebar"},"overview/app-container":{"id":"overview/app-container","title":"App Container","description":"ExpressoTS leverages InversifyJS for its Inversion of Control (IoC) container capabilities, providing a robust system for dependency injection. This type-aware container facilitates object instantiation, resolution, and life cycle management, enabling the creation of complex dependencies with minimal code.","sidebar":"tutorialSidebar"},"overview/application":{"id":"overview/application","title":"Application","description":"At the heart of an ExpressoTS application lies the App class. It serves as the foundation for creating and configuring the server. Additionally, the App class allows middleware and providers to be configured in the server bootstrapping process. The App class also provides lifecycle hooks that allow developers to execute code before, after, and on server shutdown. This section provides an overview of the ExpressoTS application architecture, its components, and the workflow of an ExpressoTS application.","sidebar":"tutorialSidebar"},"overview/controller":{"id":"overview/controller","title":"Controllers","description":"Controllers act as the primary interface between the client and server in ExpressoTS applications. They handle incoming requests, validate payloads against an input DTO, and emit responses in the DTO pattern. In essence, controllers bridge the communication between clients and service layers, also known as use-cases.","sidebar":"tutorialSidebar"},"overview/decorators":{"id":"overview/decorators","title":"Decorators","description":"Here is a complete list of all decorators available in ExpressoTS as well as a brief description of what they do.","sidebar":"tutorialSidebar"},"overview/dependencies":{"id":"overview/dependencies","title":"Dependencies","description":"The purpose of this section is to list all dependencies used by ExpressoTS and our vision about dependency management.","sidebar":"tutorialSidebar"},"overview/di":{"id":"overview/di","title":"Dependency Injection","description":"Dependency Injection (DI) is a design pattern used in software development that involves providing an object with the instances of the classes it needs to perform its tasks, rather than having it construct these instances itself. This process of providing instances is called injecting them, hence the term Dependency Injection.","sidebar":"tutorialSidebar"},"overview/entities":{"id":"overview/entities","title":"Entities","description":"Entities are the core components of an ExpressoTS application. They are the objects that are used to represent the data that is going to be manipulated by the application.","sidebar":"tutorialSidebar"},"overview/error-handling":{"id":"overview/error-handling","title":"Error Handling","description":"When it comes to error handling in Node.js TypeScript APIs, there are several best practices and approaches you can follow. ExpressoTS provides a simple and easy way to handle errors.","sidebar":"tutorialSidebar"},"overview/first-steps":{"id":"overview/first-steps","title":"First steps","description":"Begin your journey with ExpressoTS, a TypeScript framework for building scalable and maintainable Node.js applications. This section guides you through the foundational concepts, setup, and architecture of ExpressoTS.","sidebar":"tutorialSidebar"},"overview/intro":{"id":"overview/intro","title":"Introduction","description":"ExpressoTS offers a refined layer over Express.js, enhancing server-side TypeScript application development. It blends the robustness of Express.js with advanced TypeScript features, streamlining the creation of scalable, maintainable, and readable applications.","sidebar":"tutorialSidebar"},"overview/middleware":{"id":"overview/middleware","title":"Middleware","description":"Middleware functions are pivotal in the request-response cycle of an ExpressoTS application, providing the capability to execute code, modify request and response objects, end the request-response cycle, or call the next middleware in the stack. It\'s essential to call next() to avoid request timeouts unless your middleware concludes the cycle.","sidebar":"tutorialSidebar"},"overview/module":{"id":"overview/module","title":"Modules","description":"Modules, or container modules in ExpressoTS, are aggregations of services\u2014primarily Controllers and their dependencies\u2014that are managed by the framework\'s container. These modules facilitate the organization, registration, and resolution of various application components within the ExpressoTS ecosystem.","sidebar":"tutorialSidebar"},"overview/providers":{"id":"overview/providers","title":"Providers","description":"In ExpressoTS, providers serve as modular enhancements to an application, encapsulating specific functionalities such as email services, authentication mechanisms, or database connections. This encapsulation is essential for preserving a loosely coupled architecture, enabling seamless swapping or updating of these functionalities without affecting the overall system.","sidebar":"tutorialSidebar"},"overview/render":{"id":"overview/render","title":"Render","description":"Express.js offers a render method to render a view and send the rendered HTML string to the client.","sidebar":"tutorialSidebar"},"overview/repositories":{"id":"overview/repositories","title":"Repositories","description":"The repository pattern in ExpressoTS provides an abstraction layer for data access, encapsulating CRUD (Create, Read, Update, Delete) operations within repository classes. These repositories act as intermediaries between the business logic and data mapping layers, using ORMs like TypeORM, Prisma or Sequelize to interact with the database.","sidebar":"tutorialSidebar"},"overview/status-code":{"id":"overview/status-code","title":"Status Code","description":"Status code is a way to represent the result of a request. These HTTP responses indicate whether a specific HTTP request has been successfully completed. Responses are grouped in five classes:","sidebar":"tutorialSidebar"},"overview/test":{"id":"overview/test","title":"Test","description":"Unit testing and integration testing are both important in any application development process because they serve different purposes.","sidebar":"tutorialSidebar"},"overview/usecase":{"id":"overview/usecase","title":"Use Cases","description":"From a UML standpoint, use cases provide a way to model the interactions between users, other systems, and a software application. A use case describes a specific scenario or flow of events between the actors and the system, leading to a certain outcome.","sidebar":"tutorialSidebar"},"providers/dto-validator":{"id":"providers/dto-validator","title":"DTO Validator","description":"The DTO Validator provider is a provider that ExpressoTS offers out-of-the-box. It is used to validate the incoming data from the client. It helps the developer to avoid runtime errors caused by missing or invalid data.","sidebar":"tutorialSidebar"},"providers/envvalidator":{"id":"providers/envvalidator","title":"Environment Validator","description":"The environment validator provider is a provider that ExpressoTS offers out-of-the-box. It is used to validate the existence of the .env file and its content.","sidebar":"tutorialSidebar"},"providers/in-memory-db":{"id":"providers/in-memory-db","title":"In Memory DB","description":"In Memory DB is a provider that uses a simple in memory database to store data. It is a class injected in the ExpressoTS dependency injection system as a singleton.","sidebar":"tutorialSidebar"},"providers/prisma":{"id":"providers/prisma","title":"Prisma Provider","description":"The ExpressoTS Prisma Provider encapsulates the robust Prisma ORM (Object-Relational Mapper) within the ExpressoTS framework, crafting a seamless interface for data operations. Prisma facilitates a sturdy, type-safe, and streamlined access to your database, ensuring that the data interactions within your applications are precise and efficient. Its robust query engine vastly simplifies database access and mitigates common bugs associated with data retrieval and manipulation.","sidebar":"tutorialSidebar"},"roadmap":{"id":"roadmap","title":"Roadmap","description":"Coming soon...","sidebar":"tutorialSidebar"},"tutorials/compression":{"id":"tutorials/compression","title":"Compression","description":"The npm compression package is a middleware that can compress response bodies for requests that traverse through it. This helps reduce the size of data that\'s sent over the network, leading to quicker response times and lower bandwidth usage. It uses the zlib library to perform gzip or deflate compression, both of which are widely supported by modern web browsers.","sidebar":"tutorialSidebar"},"tutorials/cookies":{"id":"tutorials/cookies","title":"Cookies","description":"Cookies are small pieces of data that a website sends to a user\'s web browser while the user is browsing that website. Every time the user loads the website, the browser sends the cookie back to the server to notify the website of the user\'s previous activity.","sidebar":"tutorialSidebar"}}}')}}]);